usort(
			$notifications,
			function ( $a, $b ) {
				$a_impact = isset( $a['impact'] ) ? array_key_first( $a['impact'] ) : ''; // Get the impact value if 'impact' key exists.
				$b_impact = isset( $b['impact'] ) ? array_key_first( $b['impact'] ) : ''; // Get the impact value if 'impact' key exists.

				$a_index = array_search( $a_impact, $this->custom_order, true );
				$b_index = array_search( $b_impact, $this->custom_order, true );

				if ( $a_index === $b_index ) {
					return 0;
				}

				return ( $a_index < $b_index ) ? -1 : 1;
			}
		)

array_filter(
						array_map(
							function ( $row ) use ( $keyword_lower, $post_id ) {
								$post             = get_post( $post_id );
								$post_type_object = get_post_type_object( $post->post_type );

								// Case-insensitive comparison: stored
								// keywords keep their original casing
								// (since the GET endpoint stopped lower-
								// casing them), so match the way users
								// expect — "WordPress" vs "wordpress"
								// should still de-duplicate.
								$values = array_map(
									function ( $token ) {
										$token = trim( $token );
										return function_exists( 'mb_strtolower' )
											? mb_strtolower( $token )
											: strtolower( $token );
									},
									explode( ',', $row['meta_value'] )
								);

								if ( ! in_array( $keyword_lower, $values, true ) || $post_id === $row['post_id'] ) {
									return null;
								}

								return array(
									'post_id'   => absint( $row['post_id'] ),
									'edit_link' => admin_url( sprintf( $post_type_object->_edit_link . '&action=edit', absint( $row['post_id'] ) ) ),
									'title'     => esc_html( get_the_title( $row['post_id'] ) ),
								);
